    move_uploaded_file($_FILES['file']['tmp_name'], 'uploads/' . $_FILES['file']['name']);
}
?>
```

**Fixed Code:**
```php
<?php
// FIXED: Validate file content on server side using mime_content_type and check extension
$filename = $_FILES['file']['name'];
$ext = strtolower(pathinfo($filename, PATHINFO_EXTENSION));

$allowedExts = ['png', 'jpg', 'jpeg'];
if (!in_array($ext, $allowedExts)) {
    die("Invalid file extension");
}

$finfo = finfo_open(FILEINFO_MIME_TYPE);
$mime = finfo_file($finfo, $_FILES['file']['tmp_name']);
finfo_close($finfo);

if ($mime !== 'image/png') {
    die("Invalid MIME type");
}

$safeName = bin2hex(random_bytes(16)) . '.' . $ext;
move_uploaded_file($_FILES['file']['tmp_name'], 'uploads/' . $safeName);
?>
```

**Why This Fix Works:**
Validating extensions on the server and checking MIME types using file signatures prevents attackers from executing web shell scripts (e.g. .php).

Find and fix the security vulnerability in this react code

Vulnerable code snippet:
```react
import React from 'react';

function UserProfile({ website }) {
  // VULNERABLE: If website starts with "javascript:"
  return <a href={website}>Visit Website</a>;
}
```

**Vulnerability:** React href Attribute XSS
**Severity:** HIGH
**Detail:** Passing unvalidated URLs to anchor href attributes permits execution of javascript: pseudo-protocols.

**Vulnerable Code:**
```react
import React from 'react';

function UserProfile({ website }) {
  // VULNERABLE: If website starts with "javascript:"
  return <a href={website}>Visit Website</a>;
}
```

**Fixed Code:**
```react
import React from 'react';

function UserProfile({ website }) {
  // FIXED: Validate URL protocol schema
  const isSafeUrl = (url) => {
    try {
      const parsed = new URL(url);
      return ['http:', 'https:'].includes(parsed.protocol);
    } catch (err) {
      // Allow relative paths starting with /
      return url.startsWith('/') && !url.startsWith('//');
    }
  };

  const safeUrl = isSafeUrl(website) ? website : '#';
  return <a href={safeUrl}>Visit Website</a>;
}
```

**Why This Fix Works:**
Restricting href protocols to http, https, or relative paths blocks the execution of inline JavaScript (e.g. javascript:alert(1)).

Find and fix the security vulnerability in this javascript code

Vulnerable code snippet:
```javascript
const fileUpload = require('express-fileupload');
const express = require('express');
const app = express();
app.use(fileUpload());

app.post('/upload', (req, res) => {
    const myFile = req.files.myFile;
    // VULNERABLE: Direct disk writing
    myFile.mv('/var/www/uploads/' + myFile.name, (err) => {
        res.send('Uploaded');
    });
});
```

**Vulnerability:** Unchecked File Upload Extension
**Severity:** HIGH
**Detail:** Saving uploaded files directly using user-supplied names without checking file extensions can write malicious scripts.

**Vulnerable Code:**
```javascript
const fileUpload = require('express-fileupload');
const express = require('express');
const app = express();
app.use(fileUpload());

app.post('/upload', (req, res) => {
    const myFile = req.files.myFile;
    // VULNERABLE: Direct disk writing
    myFile.mv('/var/www/uploads/' + myFile.name, (err) => {
        res.send('Uploaded');
    });
});
```

**Fixed Code:**
```javascript
const fileUpload = require('express-fileupload');
const express = require('express');
const path = require('path');
const app = express();
app.use(fileUpload());

app.post('/upload', (req, res) => {
    const myFile = req.files.myFile;
    // FIXED: Enforce strict file extension whitelist and generate a safe name
    const allowedExtensions = ['.png', '.jpg', '.jpeg', '.gif'];
    const fileExtension = path.extname(myFile.name).toLowerCase();

    if (!allowedExtensions.includes(fileExtension)) {
        return res.status(400).send('Invalid file format');
    }

    const safeName = Date.now() + '_' + Math.random().toString(36).substring(2) + fileExtension;
    myFile.mv('/var/www/uploads/' + safeName, (err) => {
        if (err) return res.status(500).send(err);
        res.send('Uploaded');
    });
});
```

**Why This Fix Works:**
Whitelisting permitted extensions prevents users from uploading active scripts (like .js, .jsp, or .php) that could be compiled by web servers.

